INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 106001, -363.0, 0.0, 7, 1, "キャル", 1, 1, "2015/12/17 15:00:00", 0, "たまには\n協力するのもいいんじゃない？\nあたしも手を貸してあげる", "2030/12/17 14:59:59", 7001);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 105901, -363.0, 0.0, 7, 1, "コッコロ", 1, 1, "2015/12/17 15:00:00", 0, "多くの方と協力して\n戦えるようです\n主さまなら、さぞ\nご活躍なさることでしょう", "2030/12/17 14:59:59", 7002);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 105801, -363.0, 0.0, 7, 1, "ペコリーヌ", 1, 1, "2015/12/17 15:00:00", 0, "たくさんの人と一緒に\n協力バトルです！\nがんばりましょう☆", "2030/12/17 14:59:59", 7003);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 105801, -363.0, 0.0, 10, 1, "ペコリーヌ", 1, 1, "2015/12/17 15:00:00", 0, "ジュエルを食べ物…\nいえ、貴重品と交換できます！", "2030/12/17 14:59:59", 10001);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 106001, -363.0, 0.0, 10, 1, "キャル", 1, 1, "2015/12/17 15:00:00", 0, "ジュエルはよく考えて\n使うことね\n無駄遣い厳禁！", "2030/12/17 14:59:59", 10002);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 105901, -363.0, 0.0, 10, 1, "コッコロ", 1, 1, "2015/12/17 15:00:00", 0, "主さまのジュエルで\n貴重な品々を購入できます\nですが、無駄遣いは\n『めっ』でございますよ", "2030/12/17 14:59:59", 10003);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (2104010, 0.0, 106401, -363.0, 0.0, 10, 2, "シェフィ", 1, 1, "2015/12/17 15:00:00", 0, "ジュエルがあれば\n貴重品と交換できるみたい\n大事に使いましょうね", "2030/12/17 14:59:59", 10004);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 105801, -416.5, 0.0, 12, 1, "ペコリーヌ", 1, 1, "2015/12/17 15:00:00", 0, "特定の条件を達成すると\n報酬がもらえますよ！\nがんばりましょう♪　", "2030/12/17 14:59:59", 12001);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 106001, -363.0, 0.0, 13, 1, "キャル", 1, 1, "2015/12/17 15:00:00", 0, "思い出が詰まってるって\nいろいろあったけど\n振り返るのもいいんじゃない？", "2030/12/17 14:59:59", 13001);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 105901, -363.0, 0.0, 13, 1, "コッコロ", 1, 1, "2015/12/17 15:00:00", 0, "主さまとの楽しい日々…\nこちらで何度でも\n思い返しましょう♪", "2030/12/17 14:59:59", 13002);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (2104010, 0.0, 106401, -363.0, 0.0, 13, 2, "シェフィ", 1, 1, "2015/12/17 15:00:00", 0, "みんなとの大切な思い出が\nたくさん詰まってるのね\n一緒に振り返って、\n心に刻みたいわ", "2030/12/17 14:59:59", 13003);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 105801, -363.0, 0.0, 13, 1, "ペコリーヌ", 1, 1, "2015/12/17 15:00:00", 0, "女の子との思い出が\nたくさん見られますよ！\nヒューヒュー♪\nモテモテですねー☆", "2030/12/17 14:59:59", 13004);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 105901, -363.0, 0.0, 14, 1, "コッコロ", 1, 1, "2015/12/17 15:00:00", 0, "育成に必要なアイテムが\n獲得できるクエストです\nわたくし、主さまのために、\n強くなりますよ", "2030/12/17 14:59:59", 14001);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (2104010, 0.0, 106401, -363.0, 0.0, 14, 2, "シェフィ", 1, 1, "2015/12/17 15:00:00", 0, "このクエストを攻略すると、\nアイテムが手に入るらしいわ。\nもっと強くなるために、\n一生懸命がんばるわね！", "2030/12/17 14:59:59", 14002);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 105801, -363.0, 0.0, 14, 1, "ペコリーヌ", 1, 1, "2015/12/17 15:00:00", 0, "このクエストを攻略すれば、\nアイテムがもらえますよ\nたくさん集めて、どんどん\n強くなっちゃいましょう！", "2030/12/17 14:59:59", 14003);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 106001, -363.0, 0.0, 14, 1, "キャル", 1, 1, "2015/12/17 15:00:00", 0, "クエストを攻略すると、\nアイテムが手に入るんだって\nもらえるものは、\nもらっておきましょ！", "2030/12/17 14:59:59", 14004);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 105901, -470.0, 0.0, 15, 1, "コッコロ", 1, 1, "2015/12/17 15:00:00", 0, "主さま、旅の準備を整えて\nより充実した冒険をいたし\nましょう", "2030/12/17 14:59:59", 15001);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (2104010, 0.0, 106401, -363.0, 0.0, 16, 2, "シェフィ", 1, 1, "2015/12/17 15:00:00", 0, "ねぇ…クランに加入してみない？\n一人も楽しいけど、みんなと\n一緒も賑やかでいいと思うの", "2030/12/17 14:59:59", 16001);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 105801, -363.0, 0.0, 16, 1, "ペコリーヌ", 1, 1, "2015/12/17 15:00:00", 0, "クランに加入してみませんか？\nみんなといっしょに冒険した方が、\n楽しいですよ！", "2030/12/17 14:59:59", 16002);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 106001, -363.0, 0.0, 16, 1, "キャル", 1, 1, "2015/12/17 15:00:00", 0, "クランに入れるらしいわよ\nせっかくだから入ってみたら？\nけっこう楽しいみたいよ♪", "2030/12/17 14:59:59", 16003);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 105901, -363.0, 0.0, 16, 1, "コッコロ", 1, 1, "2015/12/17 15:00:00", 0, "こちらでクランに加入できます\n素敵なクランがたくさんあって、\n目移りしてしまいますね", "2030/12/17 14:59:59", 16004);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 105901, -363.0, 0.0, 17, 1, "コッコロ", 1, 1, "2015/12/17 15:00:00", 0, " こちらではクランバトルに\n 参加された仲間のみなさんの\n 活躍を振り返ることができます", "2030/12/17 14:59:59", 17002);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 106001, -363.0, 0.0, 25, 1, "キャル", 1, 1, "2015/12/17 15:00:00", 0, "模擬戦の戦績もアンタが\n気に入ったものがあれば\n記録しておけるのね", "2030/12/17 14:59:59", 17004);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 105901, -363.0, 0.0, 25, 1, "コッコロ", 1, 1, "2015/12/17 15:00:00", 0, "主さま、今回のクランバトルでの\nご活躍が記録されています\nバトルの参考にいたしましょう", "2030/12/17 14:59:59", 17005);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (2104010, 0.0, 106401, -363.0, 0.0, 25, 2, "シェフィ", 1, 1, "2015/12/17 15:00:00", 0, "今回のクランバトルの調子は\nどうかしら？\n戦績を見れば、次のバトルに\n活かせるかもしれないわ", "2030/12/17 14:59:59", 17006);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 105801, -363.0, 0.0, 25, 1, "ペコリーヌ", 1, 1, "2015/12/17 15:00:00", 0, "今回のクランバトルでの戦績を\nおさらいできますよ！\n私にも見せてください☆", "2030/12/17 14:59:59", 17007);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 190801, -363.0, 0.0, 18, 1, "カリン", 1, 1, "2015/12/17 15:00:00", 0, "ようこそ！\nこちらでは、\nギルドハウスで流れる音楽の\n変更や購入が出来ますよ", "2030/12/17 14:59:59", 18001);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 190801, -363.0, 0.0, 18, 1, "カリン", 2, 1, "2015/12/17 15:00:00", 0, "ＢＧＭの変更や購入は、こちらから\nできますよ\n素敵な音楽を、たくさんご用意\nいたしました！", "2030/12/17 14:59:59", 18002);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 190801, -470.0, 0.0, 19, 1, "カリン", 3, 1, "2015/12/17 15:00:00", 0, "ギルドハウスの\nＢＧＭを変更できますよ\nあなたの好きな曲、\n私にも聴かせてくださいね", "2030/12/17 14:59:59", 19001);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 190801, -470.0, 0.0, 19, 1, "カリン", 4, 1, "2015/12/17 15:00:00", 0, "こちらでは、ＢＧＭの変更が\nできますよ\nどんな曲に変更しますか？\nふふふ、私も楽しみです♪", "2030/12/17 14:59:59", 19002);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 190801, -470.0, 0.0, 20, 1, "カリン", 5, 1, "2015/12/17 15:00:00", 0, "こちらでは、ＢＧＭを購入\nすることができますよ\n試聴することもできるので、\nじっくり選んでくださいね", "2030/12/17 14:59:59", 20001);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 190801, -470.0, 0.0, 20, 1, "カリン", 6, 1, "2015/12/17 15:00:00", 0, "いらっしゃいませ！\nＢＧＭの購入はこちらです\n素敵な曲がたくさんあって、\n目移りしちゃいますね", "2030/12/17 14:59:59", 20002);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 106001, -363.0, 0.0, 21, 1, "キャル", 1, 1, "2015/12/17 15:00:00", 0, "ここで手に入れたアイテムで\n専用装備を作成できるみたいね\nアイテムが集まったら\nさっそく作ってみましょ！", "2030/12/17 14:59:59", 21001);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 105901, -363.0, 0.0, 21, 1, "コッコロ", 1, 1, "2015/12/17 15:00:00", 0, "攻略すると珍しいアイテムが\n手に入りますよ\nこのアイテムで専用装備を\n作成できるようです", "2030/12/17 14:59:59", 21002);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (2104010, 0.0, 106401, -363.0, 0.0, 21, 2, "シェフィ", 1, 1, "2015/12/17 15:00:00", 0, "専用装備が欲しいなら\nこのクエストに挑戦するといいわ\n集めた素材でもっともっと\n強くなりましょう", "2030/12/17 14:59:59", 21003);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 105801, -363.0, 0.0, 21, 1, "ペコリーヌ", 1, 1, "2015/12/17 15:00:00", 0, "専用装備の作成に必要な\nアイテムを獲得できますよ\nたくさん集めてどんどん\n強くなりましょう！", "2030/12/17 14:59:59", 21004);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 190801, -430.0, 0.0, 22, 1, "カリン", 1, 1, "2015/12/17 15:00:00", 0, "投票はこちらです\nあなたが応援したい女の子に\n思いを込めた一票を\nお願いします！", "2030/12/17 14:59:59", 22001);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 190801, -430.0, 0.0, 22, 1, "カリン", 2, 1, "2015/12/17 15:00:00", 0, "ようこそ！\nあなたが思いを寄せるのは\nどの女の子ですか？\n応援してあげてくださいね！", "2030/12/17 14:59:59", 22002);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 190801, -430.0, 0.0, 23, 1, "カリン", 3, 1, "2015/12/17 15:00:00", 0, "たくさんの投票、\nありがとうございました\n結果発表を楽しみに\n待っていてくださいね！", "2030/12/17 14:59:59", 23001);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 190801, -430.0, 0.0, 23, 1, "カリン", 4, 1, "2015/12/17 15:00:00", 0, "ただ今、人気投票の\n集計中です\n結果が出るまでもう少しだけ\nお待ちくださいね", "2030/12/17 14:59:59", 23002);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 8.0, 109001, -385.0, 4.08, 24, 1, "エリコ（バレンタイン）", 1, 2, "2019/01/31 12:00:00", 10011, "あなた様が手伝ってくださった\nチョコレートケーキ\n美味しくないはずがありませんわ", "2030/12/17 14:59:59", 24001);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 8.0, 109001, -385.0, 5.0, 24, 1, "エリコ（バレンタイン）", 2, 2, "2019/01/31 12:00:00", 10011, "このような失敗、あなた様が\nするはずありません\nもう一度挑戦してみましょう", "2030/12/17 14:59:59", 24002);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 8.0, 109001, -385.0, 10.11, 24, 1, "エリコ（バレンタイン）", 3, 2, "2019/01/31 12:00:00", 10011, "あなた様のために\n作っているケーキを\nあなた様に手伝っていただく……\nことになるなんて……クスクス", "2030/12/17 14:59:59", 24003);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 8.0, 109001, -385.0, 4.0, 24, 1, "エリコ（バレンタイン）", 4, 2, "2019/01/31 12:00:00", 10011, "あまり気に病む必要はありませんわ\nこれからは私がたっぷりと\n時間をかけて教えて差し上げますから", "2030/12/17 14:59:59", 24004);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 8.0, 109001, -385.0, 6.0, 24, 1, "エリコ（バレンタイン）", 5, 2, "2019/01/31 12:00:00", 10011, "今回は調子が悪かった……のですか？\nあなた様が手伝ってくれたものなら\nわたしはどんなものでも……クスクス", "2030/12/17 14:59:59", 24005);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 109002, 0.0, 0.0, 24, 1, "エリコ（バレンタイン）", 6, 1, "2019/01/31 12:00:00", 10011, "あなた様が手がけた\nチョコレートケーキは\n私にとっての宝物……\n侮辱する者は生かしておきませんわ", "2030/12/17 14:59:59", 24006);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 109002, 0.0, 0.0, 24, 1, "エリコ（バレンタイン）", 7, 1, "2019/01/31 12:00:00", 10011, "とても素晴らしい出来栄えですわ！\nあなた様にふさわしい\nチョコレートケーキができました", "2030/12/17 14:59:59", 24007);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 109002, 0.0, 0.0, 24, 1, "エリコ（バレンタイン）", 8, 1, "2019/01/31 12:00:00", 10011, "私を手伝ってくれたあなた様は\nすでに私の虜……\n甘い世界に誘って差し上げますわ", "2030/12/17 14:59:59", 24008);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 109002, 0.0, 0.0, 24, 1, "エリコ（バレンタイン）", 9, 1, "2019/01/31 12:00:00", 10011, "あなた様の愛情\nしかと受け止めました\nこれが……私たちの初めての\n共同作業ですわね……クスクス", "2030/12/17 14:59:59", 24009);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 109002, 0.0, 0.0, 24, 1, "エリコ（バレンタイン）", 10, 1, "2019/01/31 12:00:00", 10011, "これは世界一の\nチョコレートケーキですわ\nだって、あなた様が腕によりをかけて\n作ってくださったんですもの", "2030/12/17 14:59:59", 24010);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 8.0, 109101, -385.0, 2.12, 24, 1, "シズル（バレンタイン）", 1, 2, "2019/01/31 12:00:00", 10011, "上手にできなくて残念だった？\nでも、弟くんの気持ちが嬉しいな\nいつだってお姉ちゃんは\nそばにいるからね♪", "2030/12/17 14:59:59", 24011);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 8.0, 109101, -385.0, 4.19, 24, 5, "シズル（バレンタイン）", 2, 2, "2019/01/31 12:00:00", 10011, "うーん、弟くんには珍しく\n緊張しちゃったのかな？\nもう一度チャレンジしてみる？", "2030/12/17 14:59:59", 24012);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 8.0, 109101, -385.0, 2.3, 24, 2, "シズル（バレンタイン）", 3, 4, "2019/01/31 12:00:00", 10011, "お姉ちゃんのお手伝い、\nよくできました！\nあー、\nまだつまみ食いしちゃダメだぞ！", "2030/12/17 14:59:59", 24013);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 109102, 0.0, 0.0, 24, 1, "シズル（バレンタイン）", 4, 1, "2019/01/31 12:00:00", 10011, "見てみて！\nスポンジに綺麗な焼き目がついてるよ\nさっすが弟くんだね！", "2030/12/17 14:59:59", 24014);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 8.0, 109101, -385.0, 5.23, 24, 5, "シズル（バレンタイン）", 5, 2, "2019/01/31 12:00:00", 10011, "まぁまぁ、落ち込まないで\n見た目は……個性的だけど、\n味は絶対美味しいはずだから！", "2030/12/17 14:59:59", 24015);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 109102, 0.0, 0.0, 24, 1, "シズル（バレンタイン）", 6, 1, "2019/01/31 12:00:00", 10011, "弟くんみたいな\n可愛いケーキができたよ！\n早く食べてみたいでしょ♪", "2030/12/17 14:59:59", 24016);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 8.0, 109101, -385.0, 5.01, 24, 1, "シズル（バレンタイン）", 7, 2, "2019/01/31 12:00:00", 10011, "あれれ？　弟くん、指に\nチョコレートがくっついてるよ？\nお姉ちゃんが舐めてあげるね、\nはぁむ！", "2030/12/17 14:59:59", 24017);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 109102, 0.0, 0.0, 24, 1, "シズル（バレンタイン）", 8, 1, "2019/01/31 12:00:00", 10011, "なかなか上手にできたんじゃない？\nでも弟くんはまだまだできる子！\nお姉ちゃん、信じてるからね", "2030/12/17 14:59:59", 24018);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 109102, 0.0, 0.0, 24, 1, "シズル（バレンタイン）", 9, 1, "2019/01/31 12:00:00", 10011, "わぁ～、\nとっても美味しそうにできたね！\n弟くん手慣れてたから\nお姉ちゃん安心して任せられちゃった！", "2030/12/17 14:59:59", 24019);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 109102, 0.0, 0.0, 24, 1, "シズル（バレンタイン）", 10, 1, "2019/01/31 12:00:00", 10011, "や～ん、弟くんが手伝ってくれた\nチョコレートケーキ！\nすっごく美味しそうにできたね♪", "2030/12/17 14:59:59", 24020);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (2104010, 0.0, 106401, -363.0, 0.0, 26, 2, "シェフィ", 1, 1, "2015/12/17 15:00:00", 0, "ここから先は神聖な場所みたい\nどんなお宝が眠っているのか、\n今から探索するのが楽しみね♪", "2030/12/17 14:59:59", 26001);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 105801, -363.0, 0.0, 26, 1, "ペコリーヌ", 1, 1, "2015/12/17 15:00:00", 0, "ここから先は神聖な場所\nみたいです！\nどんなお宝が手に入るか\n楽しみですね！", "2030/12/17 14:59:59", 26002);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 106001, -363.0, 0.0, 26, 1, "キャル", 1, 1, "2015/12/17 15:00:00", 0, "この先は神聖な場所みたい。\n手に入るお宝も並じゃないけど\n気を付けていかないと\n痛い目にあうわよ", "2030/12/17 14:59:59", 26003);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 105901, -363.0, 0.0, 26, 1, "コッコロ", 1, 1, "2015/12/17 15:00:00", 0, "ここから先は神聖な場所\nでございます。\n気を引き締めてお宝の\n調査探索に参りましょう", "2030/12/17 14:59:59", 26004);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (2104010, 0.0, 106401, -363.0, 0.0, 27, 2, "シェフィ", 1, 1, "2015/12/17 15:00:00", 0, "ここにさらなる力を得るための\nアイテムが眠っている…って\nみんな言ってるわ。ふふっ、\nそれじゃあ挑戦してみましょうか", "2030/12/17 14:59:59", 27001);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 105801, -363.0, 0.0, 27, 1, "ペコリーヌ", 1, 1, "2015/12/17 15:00:00", 0, "ここにさらなる力を得るための\nアイテムが眠っているみたい\nです！　どこから挑戦するか\n迷っちゃいますね！", "2030/12/17 14:59:59", 27002);
