INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 106001, -363.0, 0.0, 43, 1, "キャル", 1, 1, "2015/12/17 15:00:00", 0, "ここからアリーナに\n挑戦できるわよ！\nしっかり編成を考えて\nライバルに挑みなさい！", "2030/12/17 14:59:59", 43003);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 123001, -416.5, 0.0, 44, 1, "アメス", 1, 1, "2015/12/17 15:00:00", 0, "ミッションをクリアすると報酬が\n受け取れるわ。ジャンジャン\nクリアしてバリバリ強化して\nあげなさい♪", "2030/12/17 14:59:59", 43004);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 123001, -416.5, 0.0, 44, 1, "アメス", 2, 1, "2015/12/17 15:00:00", 0, "ぼんやりしてる場合じゃないわ。\n早くミッションをクリアして\n報酬を受け取ってきなさい！", "2030/12/17 14:59:59", 43005);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 123001, -416.5, 5.79, 45, 1, "アメス", 3, 2, "2015/12/17 15:00:00", 0, "ちょっとあんた、報酬が\n受け取れるじゃない！\n忘れずにチェックなさい。\nアメス様との約束よ？", "2030/12/17 14:59:59", 43006);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 123001, -371.5, 0.0, 46, 1, "アメス", 1, 1, "2015/12/17 15:00:00", 0, "はい、お疲れさま。\nここではマスタリーチケットを\n使って、マスタリー強化素材を\n手に入れることができるわよ。", "2030/12/17 14:59:59", 46001);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 104901, -416.5, 0.0, 47, 2, "シズル", 1, 2, "2015/12/17 15:00:00", 0, "呼ばれて飛び出てお姉ちゃんだよ♪\nたとえ火の中、水の中、迷宮の中っ\nこのダンジョンを踏破できるよう\n弟くんを応援してあげるからねっ♪", "2030/12/17 14:59:59", 47001);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 101101, -416.5, 9.32, 47, 1, "リノ", 1, 2, "2015/12/17 15:00:00", 0, "ほんとーに不思議な場所ですね～\nお兄ちゃんが冒険を頑張れるよう\nおまじないをかけてあげますねっ\nフレーフレー、お・兄・ちゃんっ♪", "2030/12/17 14:59:59", 47002);
INSERT INTO `v1_90ee2297c400a5adbf35c2a72cbea5d5ee0f6e6a4e852e7247afc8dbb4427937` VALUES (0, 0.0, 104901, -470.0, 0.0, 48, 2, "シズル", 0, 2, "2015/12/17 15:00:00", 0, "", "2030/12/17 14:59:59", 48001);
